    "src": "package Main;\nimport Core.Output;\n\n// A tiny program used by ../cli/README.md to demonstrate the phorj CLI:\n// source forms (file / stdin / inline), inspection (check / parse / lex),\n// the diagnostic dictionary (explain), and clean compile/runtime faults.\nfunction main(): void {\n    int n = 6;\n    Output.printLine(\"phorj CLI demo\");\n    Output.printLine(\"n doubled = {n * 2}\");\n}"
