    "category": "realworld",
    "name": "shop",
    "src": "package Main;\nimport Core.Output;\n\n// A shopping cart with per-item discounts.\n\nenum Discount {\n    None,\n    Percent(int pct),\n    Flat(int cents),\n}\n\nclass Item {\n    constructor(private string name, private int cents, private Discount disc) {}\n\n    function nameOf(): string { return this.name; }\n\n    function price(): int {\n        return match this.disc {\n            None()     => this.cents,\n            Percent(p) => this.cents - this.cents * p / 100,\n            Flat(c)    => this.cents - c,\n        };\n    }\n}\n\n// Recursive bulk price for `n` identical units (no list folding needed).\nfunction bulk(int unit, int n): int {\n    if (n <= 0) {\n        return 0;\n    }\n    return unit + bulk(unit, n - 1);\n}\n\nfunction main(): void {\n    List<Item> cart = [\n        new Item(\"Widget\", 1000, new None()),\n        new Item(\"Gadget\", 2000, new Percent(10)),\n        new Item(\"Gizmo\", 1500, new Flat(300)),\n    ];\n    for (Item it in cart) {\n        Output.printLine(\"{it.nameOf()} = {it.price()}c\");\n    }\n    Output.printLine(\"5x Widget = {bulk(1000, 5)}c\");\n}"
