    "name": "grades",
    "src": "package Main;\nimport Core.Output;\n\nenum Grade {\n    Pass(int score),\n    Fail(int score),\n}\n\nfunction classify(int score): Grade {\n    if (score >= 50) {\n        return new Pass(score);\n    }\n    return new Fail(score);\n}\n\nfunction describe(Grade g): string {\n    return match g {\n        Pass(s) => \"PASS ({s})\",\n        Fail(s) => \"FAIL ({s})\",\n    };\n}\n\nclass Counter {\n    constructor(private int total) {}\n\n    function add(int n): int {\n        return this.total + n;\n    }\n}\n\nfunction main(): void {\n    Counter c = new Counter(100);\n    int t = c.add(23);\n    Output.printLine(\"counter total = {t}\");\n\n    List<int> scores = [80, 30, 55];\n    for (int s in scores) {\n        Grade g = classify(s);\n        string line = describe(g);\n        Output.printLine(line);\n    }\n}"
