    "category": "transpile",
    "name": "demo",
    "src": "package Main;\nimport Core.Output;\n\n// This program is also in the byte-identity sweep. `phg transpile` turns it into\n// runnable PHP 8.x — the only Phorj↔PHP-ecosystem path (output, not input).\n\nenum Shape {\n    Circle(float r),\n    Square(float side),\n}\n\nclass Named {\n    constructor(private string label) {}\n    function labelOf(): string { return this.label; }\n}\n\nfunction area(Shape s): float {\n    return match s {\n        Circle(r)    => 3.14159 * r * r,\n        Square(side) => side * side,\n    };\n}\n\nfunction main(): void {\n    Named n = new Named(\"demo\");\n    Output.printLine(\"{n.labelOf()}: circle area = {area(new Circle(2.0))}\");\n}"
